export const footerLegalDocuments = legalDocuments.filter((document) => document.footerGroup === 'legal');
export const footerCustomerDocuments = legalDocuments.filter((document) => document.footerGroup === 'customer');

export function findLegalDocument(slug: string) {
  return legalDocuments.find((document) => document.slug === slug || document.aliases?.includes(slug));
}
